# Scratch: "အကယ်၍ ဆိုရင်" ဘလောက်နဲ့ တူတယ်
moeloup = input("ရာသီဥတုဘယ်လိုလဲ? (နေသာ/မိုးရွာ): ")
if moeloup == "နေသာ":
    print("အပြင်ထွက်ကစားရအောင်!")
else:
    print("ပရိုဂရမ်းမင်းလုပ်ရအောင်!")

# Scratch: "အကယ်၍ ဆိုရင် မဟုတ်ရင် အကယ်၍ ဆိုရင်" ဘလောက်နဲ့ တူတယ်
nari = int(input("အခုဘယ်နှစ်နာရီလဲ? (0-23): "))
if nari < 10:
    print("မင်္ဂလာနံနက်ခင်းပါ!")
elif nari < 17:
    print("မင်္ဂလာနေ့လယ်ခင်းပါ!")
else:
    print("မင်္ဂလာညနေခင်းပါ!")

# Scratch: "ထပ်လုပ်" ဘလောက်နဲ့ တူတယ်
for akyin in range(5):
    print(str(akyin + 1) + " ကြိမ်မြောက်: မင်္ဂလာပါ!")
